import{_ as s,c as a,o as i,b as d}from"./app.b5c11ed0.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 11","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 11","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-08-30T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/11/index.md"}',n={},c=d('<div class="stanza"><a href="#s11.1" id="s11.1" class="num">11.1</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u0434\u0438\u043A\u0448\u0435, \u0441\u0430\u043C\u043E\u0439 \u0442\u0440\u0443\u0434\u043D\u043E\u0434\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u043E\u0439. \u0422\u0432\u043E\u0440\u044F\u0449\u0435\u0439 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435, \u0442\u0432\u043E\u0440\u044F\u0449\u0435\u0439 \u043F\u0440\u044F\u043C\u043E\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s11.2" id="s11.2" class="num">11.2</a><p>\u0414\u043B\u044F \u043D\u0435\u0435 \u043D\u0435 \u043D\u0443\u0436\u043D\u044B \u043D\u0438\u043A\u0430\u043A\u0438\u0435 \u043C\u0430\u043D\u0434\u0430\u043B\u044B, \u0436\u0435\u0440\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u044F\u043C\u044B \u0438 \u043F\u0440\u043E\u0447\u0435\u0435. \u041F\u0435\u0440\u0435\u0434 \u043D\u0435\u0439 \u043D\u0435 (\u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F) \u043D\u044C\u044F\u0441\u0430 \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0430 \u043E\u043C\u043E\u0432\u0435\u043D\u0438\u0435 - \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E .</p></div><div class="stanza"><a href="#s11.3" id="s11.3" class="num">11.3</a><p>\u0412\u043E\u0439\u0434\u044F \u0432 \u043C\u0435\u0441\u0442\u043E \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F, \u0445\u043E\u0440\u043E\u0448\u043E \u0443\u043C\u0430\u0449\u0435\u043D\u043D\u043E\u0435, \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u043E\u0435, \u043E\u0431\u0440\u0430\u0442\u0438\u0432\u0448\u0438\u0441\u044C \u043B\u0438\u0446\u043E\u043C \u043D\u0430 \u0432\u043E\u0441\u0442\u043E\u043A \u0438\u043B\u0438 \u043D\u0430 \u0441\u0435\u0432\u0435\u0440 \u043E\u0431\u043B\u0430\u0447\u0435\u043D\u043D\u044B\u0439 \u0432 \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0435 \u0446\u0432\u0435\u0442\u044B .</p></div><div class="stanza"><a href="#s11.4" id="s11.4" class="num">11.4</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0438\u044F\u044E\u0449\u0443\u044E \u0428\u0430\u043A\u0442\u0438 \u043E\u0442 \u0441\u0442\u043E\u043F \u0434\u043E \u0433\u043E\u043B\u043E\u0432\u044B, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0433\u043E\u0440\u0430\u044E\u0449\u0435\u0435 \u0442\u0435\u043B\u043E \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0430\u0445\u0430\u043C\u0443\u0434\u0440\u044B .</p></div><div class="stanza"><a href="#s11.5" id="s11.5" class="num">11.5</a><p>\u0412 \u043F\u043E\u0440\u044F\u0434\u043A\u0435 \u0430\u043D\u0443\u043B\u043E\u043C\u0430 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043C\u0430\u043B\u0438\u043D\u0438, \u044F\u0432\u043B\u044F\u044E\u0449\u0443\u044E \u0430\u043C\u0440\u0438\u0442\u0443, \u0440\u0430\u0434\u0438 \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0435\u0435 \u0432 \u0442\u0435\u043B\u043E. \u042D\u0442\u0430 \u0434\u0445\u044C\u044F\u043D\u0430 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0432 \u0443\u043C\u0435 .</p></div><div class="stanza"><a href="#s11.6" id="s11.6" class="num">11.6</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C, \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E \u0440\u0430\u043D\u0435\u0435, \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u0435 \u0430\u0434\u0445\u0432 \u0432 \u0442\u0435\u043B\u0435. \u0417\u0430\u0442\u0435\u043C, \u043E\u0447\u0438\u0441\u0442\u0438\u0432 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u044B, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0435\u0441\u0442\u0438 (\u041A\u0443\u043D\u0434\u0430\u043B\u0438\u043D\u0438) \u0428\u0430\u043A\u0442\u0438 \u043A \u0430\u043C\u0440\u0438\u0442\u0435 .</p></div><div class="stanza"><a href="#s11.7" id="s11.7" class="num">11.7</a><p>\u0412\u043E \u0432\u0441\u0435\u0445 \u043E\u0431\u0440\u044F\u0434\u0430\u0445 \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0440\u0438\u0442\u0443\u0430\u043B \u0434\u043E\u043B\u0436\u0435\u043D \u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u041C\u0430\u043B\u0438\u043D\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0439 \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0444\u0435\u0440\u044B, \u0438\u043B\u0438 \u0432\u0441\u0435\u0439 \u0432\u044B\u0441\u0448\u0435\u0439 (\u0441\u0444\u0435\u0440\u0435) \u0446\u0435\u043B\u0438\u043A\u043E\u043C, \u043E \u0412\u043E\u0437\u043B\u044E\u0431\u043B\u0435\u043D\u043D\u0430\u044F!</p></div><div class="stanza"><a href="#s11.8" id="s11.8" class="num">11.8</a><p>\u0412 \u043D\u0430\u0447\u0430\u043B\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0413\u0430\u043D\u0435\u0448\u0443 \u0434\u043B\u044F \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u0439. \u0417\u0430\u0442\u0435\u043C, \u043F\u0440\u0438\u0441\u0442\u0443\u043F\u0438\u0432 \u043A (\u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u044E) \u0441\u0432\u043E\u0435\u0433\u043E \u0433\u0443\u0440\u0443, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0441\u0435\u043C\u044C\u044E \u0433\u0443\u0440\u0443 .</p></div><div class="stanza"><a href="#s11.9" id="s11.9" class="num">11.9</a><p>\u041F\u043E\u0441\u043B\u0435 \u0413\u0430\u043D\u0435\u0448\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0442\u0438\u0442\u044C \u0432\u0441\u0435 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u043C\u0430\u043D\u0442\u0440, \u0438\u0445 \u0432\u043B\u0430\u0434\u044B\u043A\u0430\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u0430\u0440\u0433\u0445\u044C\u044E .</p></div><div class="stanza"><a href="#s11.10" id="s11.10" class="num">11.10</a><p>\u041F\u043E \u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0412\u0438\u0434\u044C\u044E. \u042D\u0442\u0430 \u0412\u0438\u0434\u044C\u044F \u0435\u0441\u0442\u044C \u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0438. \u041F\u043E\u0441\u043B\u0435 (\u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u044F) \u043C\u0430\u043D\u0442\u0440\u044B, \u0432\u0438\u0434\u044C\u0438 \u0438 \u0413\u0430\u043D\u0435\u0448\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0430\u043F\u043E\u043B\u043D\u0438\u0442\u044C\u0441\u044F \u043A\u0443\u043B\u0430 \u0428\u0430\u043A\u0442\u0438 .</p></div><div class="stanza"><a href="#s11.11" id="s11.11" class="num">11.11</a><p>\u041D\u0430 \u0432\u043E\u0441\u0442\u043E\u0447\u043D\u043E\u043C, \u044E\u0436\u043D\u043E\u043C \u0438 \u0441\u0435\u0432\u0435\u0440\u043D\u043E\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u043F\u043E\u0447\u0438\u0442\u0430\u044E\u0442\u0441\u044F \u0447\u0435\u0442\u044B\u0440\u0435 \u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435: \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u0435\u0441\u044F, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0432\u043E\u0441\u0442\u043E\u043A\u0430 \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0441\u0435\u0432\u0435\u0440\u043E-\u0432\u043E\u0441\u0442\u043E\u043A\u043E\u043C, \u0418\u043D\u0434\u0440\u0430\u043D\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 .</p></div><div class="stanza"><a href="#s11.12" id="s11.12" class="num">11.12</a><p>\u0412\u044B\u0448\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0411\u043E\u0433\u0430 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043A\u0443\u0442\u0430 (\u041A\u0428\u0410), \u0438 \u0410\u043D\u0443 \u043C\u0430\u043D\u0442\u0440\u044B, \u0434\u0436\u0438\u0432\u0443 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043F\u0430\u043B\u043A\u0438, \u0434\u0436\u0438\u0432\u0443 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u0432 \u0432\u0432\u0435\u0440\u0445\u0443 \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0430 .</p></div><div class="stanza"><a href="#s11.13" id="s11.13" class="num">11.13</a><p>\u041F\u0440\u0430\u0432\u044B\u0439 \u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u0430\u043B\u0435\u0446 \u0432\u043D\u0438\u0437\u0443, \u0437\u0430\u0442\u0435\u043C \u043B\u0435\u0432\u0430\u044F \u0433\u0440\u0443\u0434\u044C, \u043F\u043E\u0441\u043B\u0435 \u043D\u0435\u0433\u043E \u0436\u0438\u0432\u043E\u0442, \u0433\u043E\u0440\u043B\u043E, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u044B\u0435 \u043B\u0435\u0432\u044B\u043C \u0437\u0443\u0431\u0446\u043E\u043C .</p></div><div class="stanza"><a href="#s11.14" id="s11.14" class="num">11.14</a><p>\u0417\u0430\u0442\u0435\u043C \u0428\u0438\u0432\u0430 \u0438 \u044F\u0437\u044B\u043A, \u043D\u0430\u0434 \u043D\u0438\u043C - \u0432\u0435\u0440\u0445\u043D\u044F\u044F \u0447\u0435\u043B\u044E\u0441\u0442\u044C. \u0422\u0430\u043A \u043E\u0431\u0440\u0430\u0437\u0443\u0435\u0442\u0441\u044F \u0446\u0430\u0440\u044C \u043D\u0430\u0434 \u0439\u043E\u0433\u0438\u043D\u0438 \u0447\u0430\u043A\u0440\u0430\u043C\u0438 . (<em>\u041E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043C\u0430\u043D\u0442\u0440\u0430, \u043A \u0441\u043E\u0436\u0430\u043B\u0435\u043D\u0438\u044E, \u043D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u0440\u0430\u0441\u0448\u0438\u0444\u0440\u043E\u0432\u0430\u0442\u044C</em>)</p></div><div class="stanza"><a href="#s11.15" id="s11.15" class="num">11.15</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0433\u043E \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u044E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u044B\u0441\u0448\u0435\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u0442\u044C, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0443, \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0435 \u0433\u0435\u0440\u043E\u0435\u0432 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 (\u0438\u0445) \u0428\u0430\u043A\u0442\u0438 .</p></div><div class="stanza"><a href="#s11.16" id="s11.16" class="num">11.16</a><p>\u0416\u0435\u043B\u0430\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u043E\u0431\u0440\u0430\u0437 \u0428\u0440\u0438, \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u0441\u0442\u043E\u043F, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0433\u0430\u043D\u0434\u0445\u043E\u0439, \u0434\u0445\u0443\u043F\u043E\u0439 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C .</p></div><div class="stanza"><a href="#s11.17" id="s11.17" class="num">11.17</a><p>\u0417\u0430\u0442\u0435\u043C, \u043F\u0440\u0438\u0437\u0432\u0430\u0432 \u0443\u0447\u0435\u043D\u0438\u043A\u0430 \u043C\u043D\u043E\u0433\u043E\u043A\u0440\u0430\u0442\u043D\u043E \u0438 \u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0441\u043F\u044B\u0442\u0430\u043D\u043D\u043E\u0433\u043E, \u043E\u043A\u0440\u043E\u043F\u0438\u0432 (\u043F\u0440\u0438 \u043F\u043E\u043C\u043E\u0449\u0438) \u0420\u0443\u0434\u0440\u0430 \u0428\u0430\u043A\u0442\u0438, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0435\u0433\u043E \u043F\u0435\u0440\u0435\u0434 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C .</p></div><div class="stanza"><a href="#s11.18" id="s11.18" class="num">11.18</a><p>\u041E\u0433\u043B\u044F\u0434\u0435\u0432 \u0441\u0432\u043E\u0438 \u043B\u0430\u0434\u043E\u043D\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0441\u0432\u044F\u0442\u0438\u0442\u044C \u0438\u0445 \u0440\u0443\u0434\u0440\u0430 \u0428\u0430\u043A\u0442\u0438. \u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u0446\u0432\u0435\u0442\u044B \u0441 \u0440\u0443\u043A \u0441 \u0431\u043B\u0430\u0433\u043E\u0432\u043E\u043D\u0438\u044F\u043C\u0438 \u043F\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u0430\u043C \u0441\u0432\u0435\u0442\u0430 .</p></div><div class="stanza"><a href="#s11.19" id="s11.19" class="num">11.19</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0438\u0445 \u0431\u0435\u0437\u043E\u043F\u043E\u0440\u043D\u043E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0438\u0445 \u043A\u0430\u043A \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 \u0428\u0430\u043A\u0442\u0438. \u0421\u0436\u0430\u0432 \u0438\u0445 \u0441 \u0448\u0430\u043A\u0442\u0438 \u043C\u0430\u043D\u0442\u0440\u043E\u0439 \u0438 \u043D\u0435\u0442\u0440\u043E\u0439, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 (\u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438)\u0438\u0445 \u043A \u0433\u043B\u0430\u0437\u0430\u043C, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435 .</p></div><div class="stanza"><a href="#s11.20" id="s11.20" class="num">11.20</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C (\u0432 \u043D\u0438\u0445) \u0446\u0432\u0435\u0442\u043E\u043A. \u042D\u0442\u043E - \u0428\u0430\u043A\u0442\u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u0432 \u0440\u0443\u043A\u0435. \u041A\u0443\u0434\u0430 \u0443\u043F\u0430\u0434\u0435\u0442 \u0446\u0432\u0435\u0442\u043E\u043A, \u0442\u0430\u043C \u0431\u0443\u0434\u0435\u0442 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0430 \u041A\u0443\u043B\u0430 .</p></div><div class="stanza"><a href="#s11.21-22" id="s11.21-22" class="num">11.21-22</a><p>\u0417\u0430\u0442\u0435\u043C \u0435\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u043A \u043B\u0438\u0446\u0443 \u0438 \u0431\u0440\u043E\u0441\u0438\u0442\u044C \u043A \u043D\u043E\u0433\u0430\u043C (\u0443\u0447\u0435\u043D\u0438\u043A\u0430). \u0417\u0430\u0442\u0435\u043C \u0443 \u0435\u0433\u043E \u0433\u043E\u043B\u043E\u0432\u044B \u043F\u043E\u0447\u0438\u0442\u0430\u044F \u0447\u0430\u043A\u0440\u0443 (\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u043D\u0443\u044E) \u0440\u0443\u043A\u0430\u043C\u0438, \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0439\u043E\u0433\u0443 \u043F\u0443\u0441\u0442\u044C \u043F\u0440\u043E\u043F\u0443\u0441\u0442\u0438\u0442 \u0428\u0430\u043A\u0442\u0438 (\u0447\u0435\u0440\u0435\u0437 \u0440\u0443\u043A\u0438), \u043F\u043E\u043A\u0430 \u043E\u043D\u0430 \u043D\u0435 \u0432\u043E\u0439\u0434\u0435\u0442 \u0432 \u0433\u043E\u043B\u043E\u0432\u0443 (\u0443\u0447\u0435\u043D\u0438\u043A\u0430). \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u0440\u0430\u0432\u0438\u043B\u043E\u043C \xAB\u0440\u0443\u043A\u0438 \u0428\u0438\u0432\u044B\xBB, \u0442\u0432\u043E\u0440\u044F\u0449\u0438\u043C \u043F\u0440\u044F\u043C\u043E\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s11.23" id="s11.23" class="num">11.23</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u0433\u043E\u0440\u0448\u043E\u043A, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 \u043F\u043B\u043E\u0434\u0430\u043C\u0438 \u043C\u0438\u0440\u043E\u0431\u0430\u043B\u0430 \u0438 \u0442.\u0434 .. \u0421\u0434\u0435\u043B\u0430\u0432 \u0442\u0435\u043B\u043E \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u043C\u044B\u043C \u0428\u0430\u043A\u0442\u0438, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0431\u043E\u0439 \u0443\u0447\u0435\u043D\u0438\u043A\u0430 .</p></div><div class="stanza"><a href="#s11.24" id="s11.24" class="num">11.24</a><p>\u041E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u0441 \u0431\u0440\u043E\u0441\u0430\u043D\u0438\u0435\u043C \u0446\u0432\u0435\u0442\u043E\u0432 \u043F\u0440\u0430\u0432\u043E\u0439 \u0440\u0443\u043A\u043E\u0439 \u0438 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u0435\u043C \u043C\u0430\u043D\u0442\u0440\u044B, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0437\u044F\u0442\u044C \u0433\u043E\u0440\u0448\u043E\u043A, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0443\u043C\u043E\u043C \u0432 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0438 .</p></div><div class="stanza"><a href="#s11.25" id="s11.25" class="num">11.25</a><p>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \xAB\u0440\u0443\u043A\u0438 \u0428\u0438\u0432\u044B\xBB, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u044F\u0432 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u0435\u0435 \u043A \u043B\u0438\u0446\u0443. \u0421 \u044D\u0442\u0438\u043C \u0440\u0438\u0442\u0443\u0430\u043B\u043E\u043C \u043F\u043E\u0434\u043D\u043E\u0441\u0438\u0442\u0441\u044F (\u0441\u043E\u0441\u0443\u0434), \u0441\u0434\u0435\u043B\u0430\u043D\u043D\u044B\u0439 \u0438\u0437 \u0434\u0435\u0440\u0435\u0432\u0430 \u0431\u0430\u043D\u044C\u044F\u043D .</p></div><div class="stanza"><a href="#s11.26" id="s11.26" class="num">11.26</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043D\u0435\u0441\u0442\u0438 \u0437\u0443\u0431\u043E\u0447\u0438\u0442\u0441\u043A\u0443, \u043E \u0414\u0435\u0432\u0438, \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C 16 \u0430\u043D\u0433\u0443\u043B. \u0418\u0437 \u0432\u0441\u0435\u0433\u043E \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 (\u0433\u0443\u0440\u0443) \u043D\u0435 \u0440\u0430\u0437\u0434\u0443\u043C\u044B\u0432\u0430\u044F \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u0431\u0440\u0430\u0442\u044C (\u0440\u0430\u0437\u043D\u043E\u0432\u0438\u0434\u043D\u043E\u0441\u0442\u044C) \u0448\u0430\u043A\u0442\u0438\u043F\u0430\u0442\u0443;</p></div><div class="stanza"><a href="#s11.27" id="s11.27" class="num">11.27</a><p>\u041A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430 \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u044B\u0439, \u0443\u043C\u0435\u0440\u0435\u043D\u043D\u044B\u0439 \u0438 \u043F\u0440. \u041C\u0443\u0434\u0440\u044B\u0439 (\u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u0431\u0440\u0430\u0442\u044C \u0440\u0430\u0437\u043D\u043E\u0432\u0438\u0434\u043D\u043E\u0441\u0442\u044C): \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u044B\u0439, \u0443\u043C\u0435\u0440\u0435\u043D\u043D\u044B\u0439 \u0438 \u0434\u0440. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u0430\u044F \u0434\u0438\u043A\u0448\u0435\u0439, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u043C\u043E\u0439 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u043C \u0432\u044B\u0448\u0435 \u0443\u0442\u0432\u0435\u0440\u0434\u0438\u0432\u0448\u0438\u043C\u0441\u044F (\u0432 \u043D\u0435\u0439) .</p></div><div class="stanza"><a href="#s11.211.29" id="s11.211.29" class="num">11.211.29</a><p>\u041A\u043E\u0433\u0434\u0430 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0434\u0438\u043A\u0448\u0443, \u0436\u0435\u0440\u0442\u0432\u0443\u0435\u0442 (\u0432\u0441\u0435) \u0432 \u0443\u043C\u0435, \u0436\u0435\u043B\u0430\u044F \u044D\u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u044C\u0448\u0435 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u0439\u043E\u0433\u0438\u043D, \u043F\u043E\u0447\u0442\u0438\u0432 \u0412\u043B\u0430\u0434\u044B\u043A\u0443 \u041A\u0443\u043B\u044B \u0434\u043E\u043B\u0436\u0435\u043D \u0441 \u043D\u0435\u0436\u043D\u043E\u0441\u0442\u044C \u0432\u0433\u043B\u044F\u0434\u0435\u0442\u044C\u0441\u044F \u0438 \u043E\u0441\u043C\u043E\u0442\u0440\u0435\u0442\u044C \u0443\u0447\u0435\u043D\u0438\u043A\u0430, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0443\u0441\u0435\u0440\u0434\u043D\u043E \u0428\u0430\u043A\u0442\u0438 \u043E\u0442 \u0441\u0442\u043E\u043F \u0434\u043E \u0433\u043E\u043B\u043E\u0432\u044B;</p></div><div class="stanza"><a href="#s11.30-31" id="s11.30-31" class="num">11.30-31</a><p>\u0420\u0430\u0437\u043C\u0435\u0449\u0430\u044F \u043E\u0447\u0438\u0449\u0430\u0435\u043C\u044B\u0435 \u0430\u0434\u0445\u0432\u044B, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0432\u043E \u0432\u0441\u0435 \u0430\u0434\u0445\u0432\u044B, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0439 \u0440\u0430\u043D\u0435\u0435 \u0448\u0430\u043A\u0442\u0438 \u0442\u0430\u0442\u0442\u0432\u044B \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E. \u0412\u043E\u0439\u0434\u044F \u0432 \u043D\u0435\u0433\u043E, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u044D\u0442\u043E\u0442 \u043E\u0431\u0440\u044F\u0434. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u044F \u043A\u043E\u0440\u043D\u044F, \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u0435 \u0441\u0432\u0435\u0442\u043E\u043C \u043E\u0433\u043D\u044F \u0428\u0430\u043A\u0442\u0438 .</p></div><div class="stanza"><a href="#s11.32" id="s11.32" class="num">11.32</a><p>(\u0417\u0430\u0442\u0435\u043C) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C \u043E\u0447\u0438\u0449\u0430\u0435\u043C\u043E\u0435 \u0441 \u0447\u0438\u0441\u0442\u044B\u043C, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0443\u043C\u043E\u043C \u0432 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0438. \u0422\u0430\u043A \u0432\u0441\u0435 (\u0430\u0434\u0445\u0432\u044B) \u043E\u0447\u0438\u0449\u0430\u044E\u0442\u0441\u044F, \u0441\u0436\u0438\u0433\u0430\u0435\u043C\u044B\u0435 \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u044B\u043C (\u043E\u0433\u043D\u0435\u043C) .</p></div><div class="stanza"><a href="#s11.33" id="s11.33" class="num">11.33</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043A\u0430\u043A \u043E\u043D\u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u044E\u0442\u0441\u044F \u0432 \u0428\u0438\u0432\u0435, \u043D\u0438\u0448\u043A\u0430\u043B\u0435 \u0438\u043B\u0438 \u0432 \u0441\u0430\u043A\u0430\u043B\u0435. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0439\u043E\u0433\u0438 \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u044F\u0441\u044C \u043D\u0430 \u043F\u0443\u0442\u0438 \u0441\u043E \u0441\u0432\u043E\u0438\u043C \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u044B\u043C \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C .</p></div><div class="stanza"><a href="#s11.34" id="s11.34" class="num">11.34</a><p>\u0412\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0441\u0436\u0438\u0433\u0430\u043D\u0438\u0435 \u0446\u0432\u0435\u0442\u043A\u0430, \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u0442 \u0441\u0432\u043E\u0435\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443, \u0432\u0435\u043B\u0438\u043A\u043E\u043C\u0443\u0434\u0440\u044B\u0439, \u043E\u0447\u0438\u0449\u0430\u0435\u0442\u0441\u044F \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 \u0443\u0447\u0435\u043D\u0438\u043A\u0430 .</p></div><div class="stanza"><a href="#s11.35" id="s11.35" class="num">11.35</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u043C\u0435\u0442\u0438\u0442\u044C \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0438 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u0430\u043D\u0430\u043D\u0434\u0430 \u0438 \u0434\u0440 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u044F. (\u042D\u0442\u043E) - \u0430\u043D\u0430\u043D\u0434\u0430, \u0443\u0434\u0431\u0445\u0430\u0432\u0430, \u043A\u0430\u043C\u0439\u0430, \u043D\u0438\u0434\u0440\u0430 \u0438 \u0433\u0445\u0443\u0440\u043D\u0438 - \u043F\u044F\u0442\u0430\u044F .</p></div><div class="stanza"><a href="#s11.36" id="s11.36" class="num">11.36</a><p>\u041D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 (\u0442\u0430\u043A\u0438\u043C\u0438 \u0432\u0438\u0434\u0430\u043C\u0438) \u0448\u0430\u043A\u0442\u0438 (\u043F\u0430\u0442\u044B) \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u044B\u043C\u0438 \u043D\u0430 \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u0443\u044E, \u0443\u043C\u0435\u0440\u0435\u043D\u043D\u0443\u044E \u0438 \u0442.\u0434. \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0441\u0431\u0440\u043E\u0441\u0438\u0442\u044C \u043E\u043A\u043E\u0432\u044B \u0438 \u043F\u0440\u0438\u043D\u044F\u0442\u044C \u043E\u043A\u043E\u0432\u044B \u043F\u043E \u0441\u0432\u043E\u0435\u043C\u0443 \u0436\u0435\u043B\u0430\u043D\u0438\u044E .</p></div><div class="stanza"><a href="#s11.37" id="s11.37" class="num">11.37</a><p>\u041F\u0440\u0438\u043D\u044F\u0432 \u0438\u0445, \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0438\u0445 \u0440\u0430\u0437\u044A\u0435\u0434\u0438\u043D\u0438\u0442\u044C \u0434\u043B\u044F \u043E\u0441\u043E\u0431\u043E\u0433\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F. \u041D\u0438 \u0434\u043B\u044F \u043A\u043E\u0433\u043E \u0438\u043D\u043E\u0433\u043E \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u044D\u0442\u0430 \xAB\u043E\u0434\u0435\u0440\u0436\u0438\u043C\u043E\u0441\u0442\u044C\xBB .</p></div><div class="stanza"><a href="#s11.38" id="s11.38" class="num">11.38</a><p>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0448\u0430\u043A\u0442\u0438 \u043E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u0441\u0436\u0435\u0447\u044C \u0438\u0445 \u0441\u043D\u0430\u0440\u0443\u0436\u0438 \u0438 \u0432\u043D\u0443\u0442\u0440\u0438. \u041E\u043D\u0438 \u0441\u0436\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u0432 \u043D\u0435\u043C, \u043A\u0430\u043A \u0434\u0435\u0440\u0435\u0432\u043E \u0441 \u043E\u0442\u0441\u0435\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u043A\u043E\u0440\u043D\u044F\u043C\u0438 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430.</p>',36),l=[c];function p(t,v,e,r,m,f){return i(),a("div",null,l)}var z=s(n,[["render",p]]);export{h as __pageData,z as default};
